const userRow  = $('Postgres: Get User & Stats').first()?.json || {};
const vocabRows = $('Postgres: Get Vocabularies').all();
const userId    = $('Set: user_id').first().json.user_id;

// ── User ─────────────────────────────────────────────
const levelMap = { A1:'Beginner', A2:'Elementary', B1:'Intermediate', B2:'Upper Intermediate', C1:'Advanced', C2:'Mastery' };
const rawLevel = (userRow.user_level || 'B1').toUpperCase();

const user = {
  id:          userRow.user_id   || userId,
  name:        userRow.user_name || 'Learner',
  level:       rawLevel,
  description: levelMap[rawLevel] || rawLevel,
  avatar_url:  userRow.user_avatar || null,
  member_since: userRow.member_since || null
};

// ── Stats ─────────────────────────────────────────────
const stats = {
  totalMessages:    parseInt(userRow.total_messages   || 0),
  totalCorrections: parseInt(userRow.total_corrections || 0),
  wordsMastered:    parseInt(userRow.words_mastered    || 0),
  totalVocabs:      parseInt(userRow.total_vocabs      || 0),
  totalSessions:    parseInt(userRow.total_sessions    || 0)
};

// ── CEFR Pathway ─────────────────────────────────────
const cefrOrder = ['A1','A2','B1','B2','C1','C2'];
const cefrNames = { A1:'Beginner', A2:'Elementary', B1:'Intermediate', B2:'Upper Intermediate', C1:'Advanced', C2:'Mastery' };
const currentIdx = cefrOrder.indexOf(rawLevel);

const cefr = cefrOrder.map(function(lvl, idx) {
  if (idx < currentIdx) {
    return { level: lvl, name: cefrNames[lvl], status: 'completed', date: 'Completed' };
  } else if (idx === currentIdx) {
    // Progress heuristic: messages toward next milestone (every 100 messages = 100%)
    const progress = Math.min(Math.round((stats.totalMessages % 100)), 99);
    return {
      level: lvl,
      name: cefrNames[lvl],
      status: 'current',
      progress: progress,
      xp: stats.totalMessages + ' messages · ' + stats.wordsMastered + ' words mastered'
    };
  } else {
    return { level: lvl, name: cefrNames[lvl], status: 'locked' };
  }
});

// ── Vocabs ────────────────────────────────────────────
const vocabs = vocabRows.map(function(item) {
  const r = item.json;
  const mastered = r.is_mastered === true || r.is_mastered === 'true';
  return {
    word:        r.word,
    definition:  r.definition  || '',
    type:        r.type        || 'WORD',
    vocab_level: r.vocab_level || '',
    mastered:    mastered,
    status:      mastered ? 'Perfect Recall' : 'Needs practice'
  };
});

return [{ json: { user, stats, cefr, vocabs } }];
